LXImport(".StructVideoShowInfo")
local StructVideoInfo = LxClass("StructVideoInfo", nil)
function StructVideoInfo:StructVideoInfo()
    self._videoIndex = {} --唯一id表
    self._crateTime = 0    --创造时间
    self._reportId = 0    --战报id
    self._shareNum = 0    --分享次数
    self._playBackNum = 0    --回放次数
    self._likeNum = 0    --点赞次数
    self._winner = 0 --1 左边胜利 2 右边胜利
    self._combatType = 0 --战斗类型
    self._attackPlayer = nil--进攻者信息
    self._defensePlayer = nil--防守者信息

    self._opera = 0 --所属大类 1=全部视频， 2=个人记录, 3=个人收藏
    self._refId = 0 --所属小类，配置表VideoTypeRef refId
    self._id = 0    --唯一id
    self._serverId = 0 --战报所在服id
    self._moreInfo = nil --额外信息

    self.otherReport = nil        -- 特殊战报
end

function StructVideoInfo:CreateByPb(pb)
    self._videoIndex = pb.videoIndex
    self._refId = pb.refId
    self._crateTime = tonumber(pb.crateTime) / 1000
    self._reportId = pb.reportId
    self._shareNum = pb.shareNum
    self._playBackNum = pb.playBackNum
    self._likeNum = pb.likeNum
    self._winner = pb.winner
    self._moreInfo = JSON.decode(pb.moreInfo)
    local combatType = pb.combatType
    self._combatType = combatType

    local attackPlayer = StructVideoShowInfo:New()
    attackPlayer:CreateByPb(pb.attackPlayer)
    self._attackPlayer = attackPlayer

    local defensePlayer = StructVideoShowInfo:New()
    defensePlayer:CreateByPb(pb.defensePlayer)
    self._defensePlayer = defensePlayer

    self._id = self._videoIndex.id
    self._serverId = tonumber(self._videoIndex.serverId)

    if combatType == LCombatTypeConst.COMBAT_CROSSGRADING_RANK then
        --if combatType == LCombatTypeConst.COMBAT_CROSSGRADING_RANK then
        local report = StructCrossRankReport:New()
        report:CreateVideoCrossRankReport(pb)
        self.otherReport = report
    elseif combatType == LCombatTypeConst.COMBAT_TYPE_25 then
        self.attack = {
            playerId = pb.attackPlayer.playerId,
            power = pb.attackPlayer.power,
            grade = pb.attackPlayer.playerLevel,
            head = pb.attackPlayer.playerHead,
            name = pb.attackPlayer.playerName,
            headFrame = pb.attackPlayer.playerFrame,
            serverName = self._moreInfo.serverNameA,
            serverId = pb.attackPlayer.serverId,
        }

        self.defense = {
            playerId = pb.defensePlayer.playerId,
            power = pb.defensePlayer.power,
            grade = pb.defensePlayer.playerLevel,
            head = pb.defensePlayer.playerHead,
            name = pb.defensePlayer.playerName,
            headFrame = pb.defensePlayer.playerFrame,
            serverName = self._moreInfo.serverNameB,
            serverId = pb.defensePlayer.serverId,
        }

        local reportList = string.split(pb.reportId, "|")
        self.reportList = reportList
        self.reportServerId = self._moreInfo.serverId
        self.startTime = self._moreInfo.battleTime
        self.schedule = self._moreInfo.schedule
        self.group = self._moreInfo.group
        self.round = self._moreInfo.round

        self.winnerNumber = LxDataHelper.ParseNumber_Sign(self._moreInfo.winnerString, "|")
    end
end

