function StructVideoInfo:GetShareJson()

    local data = {}
    if self._combatType == LCombatTypeConst.COMBAT_TYPE_25 then
        data = self:GetSimuBattleInfo()
    else
        data = {
            id = self._videoIndex.id,
            combatType = self._combatType,
            serverId = self._videoIndex.serverId,
            playerName1 = self._attackPlayer:GetPlayerName(),
            playerName2 = self._defensePlayer:GetPlayerName(),
        }
    end

    return JSON.encode(data)
end

function StructVideoInfo:GetSimuBattleInfo()
    local data = {
        reportId = self.reportList,
        combatType = self._combatType,
        winner = self._winner,
        startTime = 0,
        attack = self.attack,
        defense = self.defense,
        winnerNumber = self.winnerNumber,
        serverId = self.reportServerId,
        schedule = self.schedule,
        round = self.round,
        playerName1 = self._attackPlayer:GetPlayerName(),
        playerName2 = self._defensePlayer:GetPlayerName(),
    }
    return data
end

function StructVideoInfo:GetWinNumberShow()
    local winC = 0
    local failC = 0
    for k, v in ipairs(self.winnerNumber) do
        if v == 1 then
            winC = winC + 1
        else
            failC = failC + 1
        end
    end

    return winC, failC
end

function StructVideoInfo:GetTitleName()

    local combatType = self._combatType
    local roundIndex = self:GetRound()
    local titleStr = gModelBattle:GetCombatTypeName(combatType)
    local roundName = ""
    if combatType == LCombatTypeConst.COMBAT_ARENA_PEAK_ATTACK then
        --1-6  N轮海选
        if roundIndex <= 6 then
            roundName = string.replace(ccClientText(21540), roundIndex)

        elseif roundIndex == 7 then
            roundName = ccClientText(21544)
        elseif roundIndex <= 10 then
            --计算 [21541]	[#a1#强]  64  32  16  8  

            local tempIndex = 10 - roundIndex + 1

            local strIndex = 8
            for i = 1, tempIndex do
                if i ~= 1 then
                    strIndex = strIndex * 2
                end
            end

            roundName = string.replace(ccClientText(21541), strIndex)
        else
            roundName = roundIndex == 11 and ccClientText(21542) or ccClientText(21543)
        end
        titleStr = string.replace(ccClientText(21529), titleStr, roundName)
        --elseif combatType == LCombatTypeConst.COMBAT_CROSS_SERVER_CHAMPION then --跨界周榜，有64强, 将前面1-6轮整合成“选拔赛”  --与COMBAT_ARENA_PEAK_ATTACK 都使用14 屏蔽
        --	if roundIndex <= 6 then
        --		roundName = ccClientText(21531)
        --	else
        --		roundName = ccClientText(21516 + roundIndex - 1)
        --	end
        --	titleStr = string.replace(ccClientText(21529), titleStr, roundName)
    elseif combatType == LCombatTypeConst.COMBAT_TYPE_25 then
        local detail = gModelVideoCenter:GetSimuFilterShow(self._moreInfo)
        titleStr = string.replace(ccClientText(21529), titleStr, detail)
    end

    return titleStr
end

function StructVideoInfo:GetStartTime()
    return self.startTime or 0
end

return StructVideoInfo
